# scripts/liquidity_fetch.py import datetime as dt import pandas as pd from pykrx import stock def _to_ymd(d: dt.date) -> str: return d.strftime("%Y%m%d") def _pick_any_col(df: pd.DataFrame, candidates: list[str]) -> str: for c in candidates: if c in df.columns: return c raise KeyError(f"missing columns: {candidates} / got: {list(df.columns)}") def fetch_liquidity_range(start: dt.date, end: dt.date, market: str) -> pd.DataFrame: """ market: 'KOSPI' or 'KOSDAQ' output: date, market, close, turnover """ s = _to_ymd(start) e = _to_ymd(end) # 1) Index OHLCV (close) idx = stock.get_index_ohlcv_by_date(s, e, market) idx = idx.reset_index() date_col = _pick_any_col(idx, ["날짜", "Date", "date"]) close_col = _pick_any_col(idx, ["종가", "Close", "close"]) idx_out = pd.DataFrame( { "date": pd.to_datetime(idx[date_col]).dt.date.astype(str), "market": market, "close": pd.to_numeric(idx[close_col], errors="coerce"), } ) # 2) Market trading value by date (turnover) tv = stock.get_market_trading_value_by_date(s, e, market=market) tv = tv.reset_index() tv_date_col = _pick_any_col(tv, ["날짜", "Date", "date"]) turnover_col = _pick_any_col( tv, [ "거래대금", "거래대금(원)", "거래대금합계", "TRADING_VALUE", "trading_value", "turnover", ], ) tv_out = pd.DataFrame( { "date": pd.to_datetime(tv[tv_date_col]).dt.date.astype(str), "market": market, "turnover": pd.to_numeric(tv[turnover_col], errors="coerce"), } ) out = ( idx_out.merge(tv_out, on=["date", "market"], how="outer") .sort_values(["date", "market"]) .reset_index(drop=True) ) return out ``` ```python # scripts/backfill_liquidity.py import argparse import datetime as dt from pathlib import Path import pandas as pd import sys # scripts 폴더 import 안정화 sys.path.append(str(Path(__file__).resolve().parent)) from liquidity_fetch import fetch_liquidity_range ROOT = Path(__file__).resolve().parents[1] HIST = ROOT / "data" / "history" HIST.mkdir(parents=True, exist_ok=True) OUT_FILE = HIST / "liquidity_daily.csv" def main(): ap = argparse.ArgumentParser() ap.add_argument("--start", required=True) # YYYY-MM-DD ap.add_argument("--end", required=True) # YYYY-MM-DD ap.add_argument("--market", default="BOTH") # KOSPI/KOSDAQ/BOTH args = ap.parse_args() start = dt.date.fromisoformat(args.start) end = dt.date.fromisoformat(args.end) markets = ["KOSPI", "KOSDAQ"] if args.market == "BOTH" else [args.market] frames = [fetch_liquidity_range(start, end, m) for m in markets] new_df = pd.concat(frames, ignore_index=True).sort_values(["date", "market"]) if OUT_FILE.exists(): old_df = pd.read_csv(OUT_FILE) df = pd.concat([old_df, new_df], ignore_index=True) else: df = new_df df = ( df.drop_duplicates(subset=["date", "market"], keep="last") .sort_values(["date", "market"]) .reset_index(drop=True) ) df.to_csv(OUT_FILE, index=False) print("Saved:", OUT_FILE, "rows=", len(df)) if __name__ == "__main__": main() ``` ---
